const body = $input.first().json.body || $input.first().json;

const mapa = {
  pendiente: 'quedo pendiente de confirmacion',
  confirmado: 'fue confirmado y ya lo estamos alistando',
  en_preparacion: 'se esta preparando',
  despachado: 'ya salio para entrega',
  entregado: 'fue entregado, gracias por tu compra',
  cancelado: 'fue cancelado'
};
const emojis = {
  pendiente: '🕐',
  confirmado: '✅',
  en_preparacion: '👨‍🍳',
  despachado: '🚚',
  entregado: '📦',
  cancelado: '❌'
};

return [{
  json: {
    numero_whatsapp: body.numero_whatsapp,
    texto: `${emojis[body.estado] || 'ℹ️'} Tu pedido #${body.pedido_id} ${mapa[body.estado] || body.estado}. Total: $${body.total}.`
  }
}];
